const TAU = 6.283, PHI = 1.618, INV_SQRT2 = 0.707;

const config = {
  repulsion: 4000,
  lensLerp: 0.004,
  damping: 0.92,
  centerPull: 0.0003,
  maxParticles: 40,
  particleDecay: 0.04,
  springK: 0.06
};

const points = [
  { id: 'hub', label: 'Hub', r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha', label: 'Alpha', r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta', label: 'Beta', r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma', label: 'Gamma', r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta', label: 'Delta', r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

const springs = [
  { a: 'hub', b: 'alpha', rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta', rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma', rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta', rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta', rest: 200, k: 0.002 },
  { a: 'gamma', b: 'epsilon', rest: 220, k: 0.002 },
  { a: 'delta', b: 'beta', rest: 200, k: 0.002 }
];

const lens = { x: 400, y: 300, zoom: 1 };
const focus = { x: 400, y: 300, zoom: 1 };
const stream = [];
let cycle = 0;

function pointById(id) {
  return points.find(p => p.id === id) || null;
}

function updatePhysics() {
  for (let i = 0; i < points.length; i++) {
    for (let j = i + 1; j < points.length; j++) {
      const dx = points[i].x - points[j].x;
      const dy = points[i].y - points[j].y;
      const dist = Math.sqrt(dx * dx + dy * dy) || 1;
      const force = config.repulsion / (dist * dist);
      const fx = (dx / dist) * force;
      const fy = (dy / dist) * force;
      points[i].vx += fx; points[i].vy += fy;
      points[j].vx -= fx; points[j].vy -= fy;
    }
  }

  for (const s of springs) {
    const a = pointById(s.a), b = pointById(s.b);
    if (!a || !b) continue;
    const dx = b.x - a.x;
    const dy = b.y - a.y;
    const dist = Math.sqrt(dx * dx + dy * dy) || 1;
    const force = (s.k || config.springK) * (dist - s.rest);
    const fx = (dx / dist) * force;
    const fy = (dy / dist) * force;
    a.vx += fx; a.vy += fy;
    b.vx -= fx; b.vy -= fy;
  }

  for (const p of points) {
    p.vx *= config.damping;
    p.vy *= config.damping;
    p.vx += (400 - p.x) * config.centerPull;
    p.vy += (300 - p.y) * config.centerPull;
    p.x += p.vx;
    p.y += p.vy;
  }
}

function emitParticle() {
  if (stream.length >= config.maxParticles) return;
  const src = points[Math.floor(Math.random() * points.length)];
  const angle = Math.random() * TAU;
  const speed = 0.3 + Math.random() * INV_SQRT2;
  stream.push({
    x: src.x,
    y: src.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * PHI * INV_SQRT2
  });
}

function updateParticles() {
  for (let i = stream.length - 1; i >= 0; i--) {
    const p = stream[i];
    p.x += p.vx;
    p.y += p.vy;
    p.vx *= 1 - config.particleDecay * 0.125;
    p.vy *= 1 - config.particleDecay * 0.125;
    p.age++;
    if (p.age > p.maxAge) stream.splice(i, 1);
  }
}

function updateLens() {
  lens.x += (focus.x - lens.x) * config.lensLerp;
  lens.y += (focus.y - lens.y) * config.lensLerp;
  lens.zoom += (focus.zoom - lens.zoom) * config.lensLerp;
}

function pulse() {
  updatePhysics();
  updateParticles();
  updateLens();
  if (cycle % 3 === 0) emitParticle();
  cycle++;
}

setInterval(pulse, 16);
